int* topo(int N, int** adj, int* indegree) {
    int* topo = (int*)malloc(N * sizeof(int));
    int index = 0;
    for (int i = 0; i < N; i++) {
        if (indegree[i] == 0) {
            topo[index++] = i;
        }
    }
    for (int i = 0; i < N; i++) {
        for (int j = 0; j < N; j++) {
            if (adj[topo[i]][j] == 1) {
                indegree[j]--;
                if (indegree[j] == 0) {
                    topo[index++] = j;
                }
            }
        }
    }
    return topo;
}

